+func TestSendInlineFile(t *testing.T) {
+	var buf bytes.Buffer
+	out := bufio.NewWriter(&buf)
+	SendInlineFile(out, File{
+		Name:        "thumb.png",
+		Data:        []byte{1, 2, 3},
+		WidthCells:  10,
+		HeightCells: 5,
+	})
